}

{

    //
    // Check the arguments.
    //
    ASSERT(SENT_isBaseValid(base));

    //
    // Disable the specified interrupt.
    //

    HWREG(base + SENT_O_REINT) &= ~intFlags;

}

{

    //
    // Check the arguments.
    //
    ASSERT(SENT_isBaseValid(base));

    //
    // Disable the specified interrupt.
    //
    return(HWREG(base + SENT_O_RINTFLAG) & intFlags);

}

{

