    // Check the arguments.
    //
    ASSERT(SENT_isBaseValid(base));

    sensorOffset = (SENT_MTP_TIMEOUT_STEP * (uint32_t)sensorNum) +
                    SENT_O_S1_MTP_TO;

    //
    // Configure the timout for Sensor channels.
    //

    HWREG(base + sensorOffset) = sensorTimeout;

