    ASSERT(compareNum < SENT_MTP_CMP_10);

    toggleOffset = (SENT_MTP_TOGGLETIME_STEP * (uint32_t)compareNum) +
                    SENT_O_BC_MTP_CMP1;

    //
    // Set the toggle time for MTPG output of broadcast channel.
    //

